// Validates a JWT bearer token and returns the decoded payload.
// Throws AuthError if the token is expired or has an invalid signature.
export async function validateBearerToken(token: string): Promise<TokenPayload> {
  const [header, payload, signature] = token.split('.');
  if (!header || !payload || !signature) {
    throw new AuthError('Invalid token format: expected 3 segments');
  }
  const decoded = JSON.parse(Buffer.from(payload, 'base64url').toString('utf8'));
  if (decoded.exp < Math.floor(Date.now() / 1000)) {
    throw new AuthError('Token has expired');
  }
  await verifySignature(header, payload, signature);
  return decoded as TokenPayload;
}

// Creates a database connection pool with configured min/max connections.
// Uses exponential backoff for initial connection failures.
export function createConnectionPool(config: PoolConfig): Pool {
  return new Pool({
    host: config.host,
    port: config.port,
    database: config.database,
    user: config.user,
    password: config.password,
    min: config.minConnections ?? 2,
    max: config.maxConnections ?? 10,
    idleTimeoutMillis: 30000,
    connectionTimeoutMillis: 5000,
  });
}

// Starts a file system watcher on the given root directory.
// Emits change events for modified files, debounced by 300ms.
export function createFsWatcher(root: string, onChange: (path: string) => void): Disposable {
  const watcher = watch(root, { recursive: true });
  let debounceTimer: ReturnType<typeof setTimeout> | null = null;
  watcher.on('change', (event, filename) => {
    if (!filename) return;
    if (debounceTimer) clearTimeout(debounceTimer);
    debounceTimer = setTimeout(() => onChange(join(root, String(filename))), 300);
  });
  return { dispose: () => watcher.close() };
}

// Performs cosine similarity search against the LanceDB vector table.
// Returns top-k results sorted by descending similarity score.
export async function vectorSearch(
  table: Table,
  queryVector: number[],
  limit: number,
  filter?: string
): Promise<SearchResult[]> {
  let query = table.vectorSearch(queryVector).limit(limit);
  if (filter) query = query.where(filter);
  const rows = await query.toArray();
  return rows.map(row => ({
    chunk_id: row.chunk_id as string,
    score: row._distance as number,
    content: row.content as string,
    file_path: row.file_path as string,
    start_line: row.start_line as number,
    end_line: row.end_line as number,
  }));
}

// Express error handling middleware — catches all unhandled errors.
// Formats them into a consistent JSON error response with the correct HTTP status.
export function errorMiddleware(
  err: Error,
  req: Request,
  res: Response,
  next: NextFunction
): void {
  const status = (err as HttpError).status ?? 500;
  const message = status >= 500 ? 'Internal server error' : err.message;
  console.error(`[error] ${req.method} ${req.path}: ${err.message}`);
  res.status(status).json({ error: message, code: (err as HttpError).code ?? 'unknown' });
}

// Loads application configuration from environment variables with validation.
// Throws ConfigError if required fields are missing or malformed.
export function loadConfig(): AppConfig {
  const port = parseInt(process.env.PORT ?? '3000', 10);
  const databaseUrl = process.env.DATABASE_URL;
  if (!databaseUrl) throw new ConfigError('DATABASE_URL is required');
  const jwtSecret = process.env.JWT_SECRET;
  if (!jwtSecret) throw new ConfigError('JWT_SECRET is required');
  const maxConnections = parseInt(process.env.DB_MAX_CONNECTIONS ?? '10', 10);
  return { port, databaseUrl, jwtSecret, maxConnections, nodeEnv: process.env.NODE_ENV ?? 'development' };
}

// Sends texts to the embedding API in batches, respecting rate limits.
// Retries failed batches with exponential backoff (max 5 attempts).
export async function embedBatched(
  texts: string[],
  config: EmbeddingConfig,
  batchSize = 100
): Promise<number[][]> {
  const results: number[][] = [];
  for (let i = 0; i < texts.length; i += batchSize) {
    const batch = texts.slice(i, i + batchSize);
    const embeddings = await embedWithRetry(batch, config);
    results.push(...embeddings);
    if (i + batchSize < texts.length) {
      await new Promise(r => setTimeout(r, config.batchDelayMs ?? 0));
    }
  }
  return results;
}

// Scans a directory for changed files using SHA-256 content hashes.
// Returns only files whose hash differs from the previously stored value.
export async function scanForChanges(
  root: string,
  storedHashes: Map<string, string>
): Promise<ChangedFile[]> {
  const changed: ChangedFile[] = [];
  for await (const filePath of walkFiles(root)) {
    const content = await fs.readFile(filePath, 'utf8');
    const hash = createHash('sha256').update(content).digest('hex');
    const relative = path.relative(root, filePath).replace(/\\/g, '/');
    if (storedHashes.get(relative) !== hash) {
      changed.push({ path: relative, hash, content });
    }
  }
  return changed;
}

// In-memory background job queue with AbortController cancellation support.
// Each job runs asynchronously and can be individually cancelled by job ID.
export class JobQueue {
  private readonly jobs = new Map<string, JobState>();

  async enqueue(
    projectId: string,
    fn: (signal: AbortSignal) => Promise<void>
  ): Promise<string> {
    const jobId = crypto.randomUUID();
    const controller = new AbortController();
    const state: JobState = { jobId, projectId, status: 'running', controller };
    this.jobs.set(jobId, state);
    fn(controller.signal)
      .then(() => { state.status = 'done'; })
      .catch(err => { state.status = 'failed'; state.error = String(err); });
    return jobId;
  }

  cancel(jobId: string): boolean {
    const job = this.jobs.get(jobId);
    if (!job) return false;
    job.controller.abort();
    job.status = 'cancelled';
    return true;
  }
}

// Handles the search_code MCP tool call.
// Returns formatted search results or a structured error on failure.
export async function handleSearchCode(
  args: { project_id: string; query: string; limit?: number; branch?: string }
): Promise<McpResult> {
  const project = registry.getProject(args.project_id);
  if (!project) {
    return mcpError('project_not_found', `Project '${args.project_id}' not found in registry`);
  }
  const results = await searchCode(project, args.query, args.limit ?? 10, args.branch);
  if (results.length === 0) {
    return mcpError('no_results', `No chunks found for query in project '${args.project_id}'`);
  }
  return { content: [{ type: 'text', text: JSON.stringify(results, null, 2) }] };
}

// Registry of source plugins, keyed by the source type string.
// Plugins define how to chunk and incrementally index a particular data source.
const PLUGINS: Record<string, SourcePlugin> = {};

export function registerPlugin(type: string, plugin: SourcePlugin): void {
  if (PLUGINS[type]) throw new Error(`Plugin already registered for type: ${type}`);
  PLUGINS[type] = plugin;
}

export function getPlugin(type: string): SourcePlugin {
  const plugin = PLUGINS[type];
  if (!plugin) throw new Error(`No plugin registered for source type: ${type}`);
  return plugin;
}

export function listPluginTypes(): string[] {
  return Object.keys(PLUGINS);
}

// Walks the Tree-sitter AST to extract named top-level declarations.
// Returns function, class, and method nodes with their source ranges.
export function extractDeclarations(tree: Tree, source: string): Declaration[] {
  const declarations: Declaration[] = [];
  const cursor = tree.walk();
  function walk(): void {
    const node = cursor.currentNode;
    if (isDeclarationNode(node.type)) {
      declarations.push({
        type: node.type,
        name: findNodeName(node) ?? '(anonymous)',
        startLine: node.startPosition.row + 1,
        endLine: node.endPosition.row + 1,
        text: source.slice(node.startIndex, node.endIndex),
      });
    }
    if (cursor.gotoFirstChild()) { walk(); cursor.gotoParent(); }
    if (cursor.gotoNextSibling()) walk();
  }
  walk();
  return declarations;
}

// Resolves the current Git branch name for the given repository root.
// Returns '*' for non-code sources that do not track branches.
export function resolveBranch(root: string, sourceType: string): string {
  if (sourceType !== 'code') return '*';
  try {
    const branch = execSync('git rev-parse --abbrev-ref HEAD', {
      cwd: root,
      encoding: 'utf8',
      stdio: ['ignore', 'pipe', 'ignore'],
    }).trim();
    return branch || 'HEAD';
  } catch {
    return 'HEAD';
  }
}

// Executes a fetch with exponential backoff on 429 and 5xx responses.
// Gives up after maxAttempts attempts and re-throws the final error.
export async function fetchWithRetry(
  url: string,
  options: RequestInit,
  maxAttempts = 5
): Promise<Response> {
  let delay = 1000;
  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    const res = await fetch(url, options);
    if (res.ok) return res;
    if ((res.status === 429 || res.status >= 500) && attempt < maxAttempts - 1) {
      await new Promise(r => setTimeout(r, delay));
      delay = Math.min(delay * 2, 30000);
      continue;
    }
    throw new Error(`HTTP ${res.status}: ${await res.text()}`);
  }
  throw new Error('fetchWithRetry: exhausted all attempts');
}

// Fetches GitLab issues updated after the given cursor timestamp.
// Uses cursor-based pagination — yields pages until no more issues are returned.
export async function* fetchIssuesSince(
  baseUrl: string,
  projectId: string,
  token: string,
  cursor?: string
): AsyncGenerator<GitLabIssue[]> {
  let updatedAfter = cursor;
  while (true) {
    const params = new URLSearchParams({ state: 'all', per_page: '100' });
    if (updatedAfter) params.set('updated_after', updatedAfter);
    const res = await fetch(`${baseUrl}/api/v4/projects/${projectId}/issues?${params}`, {
      headers: { 'PRIVATE-TOKEN': token },
    });
    if (!res.ok) throw new Error(`GitLab API ${res.status}: ${await res.text()}`);
    const issues: GitLabIssue[] = await res.json();
    if (issues.length === 0) break;
    yield issues;
    updatedAfter = issues[issues.length - 1].updated_at;
  }
}

// Creates a PostgreSQL connection pool with connection recycling.
// MinPoolSize=2, MaxPoolSize=20, connection lifetime 300 seconds.
public class DatabaseConnectionPool
{
    private readonly string _connectionString;

    public DatabaseConnectionPool(string connectionString)
    {
        _connectionString = connectionString +
            ";Minimum Pool Size=2;Maximum Pool Size=20;Connection Lifetime=300";
    }

    public async Task<NpgsqlConnection> GetConnectionAsync(CancellationToken ct = default)
    {
        var conn = new NpgsqlConnection(_connectionString);
        await conn.OpenAsync(ct);
        return conn;
    }
}

// Invalidates distributed cache entries associated with the given tag.
// Fetches the list of affected keys, removes them all, then removes the tag index.
public async Task InvalidateByTagAsync(string tag, CancellationToken ct = default)
{
    var keys = await _cache.GetAsync<List<string>>($"tag:{tag}", ct);
    if (keys == null || keys.Count == 0) return;
    var removeTasks = keys.Select(key => _cache.RemoveAsync(key, ct));
    await Task.WhenAll(removeTasks);
    await _cache.RemoveAsync($"tag:{tag}", ct);
    _logger.LogInformation(
        "Cache invalidated for tag {Tag}: {Count} entries removed", tag, keys.Count);
}

// Runs pending database schema migrations in version order.
// Each migration executes inside its own transaction; already-applied ones are skipped.
public async Task MigrateAsync(IDbConnection connection, CancellationToken ct = default)
{
    var applied = await GetAppliedMigrationsAsync(connection, ct);
    var pending = _migrations
        .Where(m => !applied.Contains(m.Name))
        .OrderBy(m => m.Version);
    foreach (var migration in pending)
    {
        using var tx = connection.BeginTransaction();
        await migration.ApplyAsync(connection, ct);
        await RecordMigrationAsync(connection, migration.Name, ct);
        tx.Commit();
        _logger.LogInformation("Applied migration: {Name}", migration.Name);
    }
}

// Refreshes an expired access token using the stored refresh token.
// Updates the token store on success; throws TokenExpiredException if refresh is also expired.
public async Task<TokenPair> RefreshAccessTokenAsync(
    string refreshToken, CancellationToken ct = default)
{
    var payload = _jwtService.DecodeToken(refreshToken);
    if (payload.ExpiresAt < DateTimeOffset.UtcNow)
        throw new TokenExpiredException("Refresh token has expired. Please log in again.");
    var user = await _userRepository.FindByIdAsync(payload.UserId, ct);
    var newAccess = _jwtService.GenerateAccessToken(user);
    var newRefresh = _jwtService.GenerateRefreshToken(user);
    await _tokenStore.ReplaceAsync(refreshToken, newRefresh, ct);
    return new TokenPair(newAccess, newRefresh);
}

// Builds a PostgreSQL full-text search query with weighted columns.
// Title column has weight A (highest), body has weight B.
public string BuildFtsQuery(string searchTerm, string lang = "german")
{
    var sanitized = Regex.Replace(searchTerm, @"[^\w\s]", " ").Trim();
    var parts = sanitized.Split(' ', StringSplitOptions.RemoveEmptyEntries);
    var tsQuery = string.Join(" & ", parts.Select(p => $"{p}:*"));
    return $"""
        SELECT id, title, ts_rank_cd(search_vector, query) AS rank
        FROM posts, to_tsquery('{lang}', '{tsQuery}') query
        WHERE search_vector @@ query
        ORDER BY rank DESC
        LIMIT 50
        """;
}

/**
 * Проверяет токен авторизации пользователя.
 * Возвращает данные пользователя или выбрасывает исключение при невалидном токене.
 * @param token - JWT токен из заголовка Authorization: Bearer <token>
 */
export async function verifyUserToken(token: string): Promise<User> {
  const payload = await jwt.verify(token, process.env.JWT_SECRET!);
  const user = await userRepository.findById(payload.sub);
  if (!user || !user.isActive) {
    throw new UnauthorizedError('User not found or inactive');
  }
  return user;
}

// Выполняет поиск по векторному индексу и возвращает топ-N релевантных результатов.
// Фильтрация по project_id обязательна для изоляции данных между проектами.
export async function findSimilarChunks(
  queryEmbedding: number[],
  projectId: string,
  limit = 10
): Promise<CodeChunk[]> {
  // Косинусное сходство встроено в LanceDB — никаких внешних вычислений не нужно
  const results = await vectorTable
    .search(queryEmbedding)
    .where(`project_id = '${projectId}'`)
    .limit(limit)
    .toArray();
  return results.map(mapRowToChunk);
}

// Обработчик ошибок для Express — перехватывает все необработанные исключения.
// Форматирует ошибку в JSON-ответ с корректным HTTP-статусом.
export function handleError(err: AppError, req: Request, res: Response): void {
  // Логируем только серверные ошибки (5xx), клиентские ошибки — только в debug-режиме
  if (err.statusCode >= 500) {
    logger.error({ err, path: req.path }, 'Внутренняя ошибка сервера');
  } else {
    logger.debug({ err, path: req.path }, 'Клиентская ошибка');
  }
  res.status(err.statusCode).json({
    error: err.code,
    message: err.isPublic ? err.message : 'Произошла ошибка. Попробуйте позже.',
  });
}

// 监听文件系统变化，当代码文件被修改时触发重新索引。
// 使用防抖处理频繁的文件变更事件，避免过度触发索引任务。
export class FileSystemWatcher {
  private watcher: FSWatcher | null = null;

  start(root: string, onChange: (path: string) => void): void {
    // 忽略隐藏文件和 node_modules 目录
    this.watcher = watch(root, { recursive: true });
    const debouncedChange = debounce(onChange, 300);
    this.watcher.on('change', (event, filename) => {
      if (filename) debouncedChange(join(root, String(filename)));
    });
  }

  stop(): void {
    this.watcher?.close();
    this.watcher = null;
  }
}

/**
 * 将文本批量转换为向量嵌入。
 * 自动处理 API 限速，使用指数退避重试策略。
 * @param texts - 待嵌入的文本列表
 * @param batchSize - 每次 API 调用的最大文本数量，默认 100
 */
export async function batchEmbed(texts: string[], batchSize = 100): Promise<number[][]> {
  const vectors: number[][] = [];
  for (let i = 0; i < texts.length; i += batchSize) {
    const batch = texts.slice(i, i + batchSize);
    const response = await embeddingClient.create({ model: config.model, input: batch });
    vectors.push(...response.data.map(d => d.embedding));
  }
  return vectors;
}
